        return [bin(i).count('1') for i in range(n + 1)]

solutions.python:
class Solution:
    def countBits(self, n: int):
        ans = [0] * (n + 1)
        for i in range(1, n + 1):
            ans[i] = ans[i & (i - 1)] + 1
        return ans

